import React, { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";
import { getEachActivities } from "../../features/Activity/ActivitySlice";
import { Tag, Button, Tooltip, Avatar } from "antd";
import { useParams, Link } from "react-router-dom";
import ImageModal from "../../components/ImageModel";
import Loading from "../../utils/Loading";
import { 
  UserCircle, 
  Tag as TagIcon, 
  Activity, 
  Terminal, 
  ChevronLeft, 
  Box, 
  Clock, 
  ShieldCheck, 
  Cpu,
  Monitor,
  Database,
  Search,
  Zap,
  Layers
} from "lucide-react";

/**
 * Premium Operational Log Detail View
 * High-end "Pulse Core" diagnostic aesthetic
 */
const ActivityDetail = () => {
  const { id } = useParams();
  const dispatch = useDispatch();
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedImage, setSelectedImage] = useState("");

  const openModal = (imageUrl) => {
    setSelectedImage(imageUrl);
    setIsModalOpen(true);
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setSelectedImage("");
  };

  useEffect(() => {
    setLoading(true);
    dispatch(getEachActivities(id)).finally(() => setLoading(false));
  }, [dispatch, id]);

  const activityLog = useSelector((state) => state.activity.Eachactivities);

  if (loading) return <div className="min-h-[60vh] flex items-center justify-center"><Loading /></div>;

  if (!activityLog || activityLog.length === 0) {
    return (
      <div className="max-w-xl mx-auto py-20 text-center">
        <Activity size={48} className="text-slate-200 mx-auto mb-6" />
        <h3 className="text-[20px] font-black text-slate-900 uppercase tracking-tighter">Null Index Exception</h3>
        <p className="text-slate-400 font-bold mt-2 uppercase tracking-widest text-xs italic">The requested operational hash could not be retrieved from the active registry.</p>
        <Link to="/superAdmin/activity" className="inline-block mt-8 text-blue-600 font-black uppercase text-[11px] tracking-widest hover:underline">← System Audit History</Link>
      </div>
    );
  }

  // Pick the first log (though usually it's one specific entry per ID)
  const log = activityLog[0];
  const timestamp = new Date(log.createdAt || log.timestamp || Date.now());

  return (
    <div className="space-y-10 pb-20 animate-in fade-in slide-in-from-bottom-6 duration-700">
      {/* Station Navigation */}
      <div className="flex items-center gap-4">
        <Link to={-1}>
          <Button 
            icon={<ChevronLeft size={20} />} 
            className="w-12 h-12 flex items-center justify-center rounded-2xl border-slate-100 bg-white text-slate-400 hover:text-blue-600 shadow-sm"
          />
        </Link>
        <div>
          <div className="flex items-center gap-2 mb-0.5">
             <div className="w-1.5 h-1.5 rounded-full bg-blue-600 animate-pulse" />
             <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest">Diagnostic Node</span>
          </div>
          <h2 className="text-[24px] font-black text-slate-900 tracking-tighter leading-none uppercase">Action Verification</h2>
        </div>
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-12 gap-10">
        {/* Left Column: Core Diagnostics */}
        <div className="xl:col-span-4 space-y-8">
            <div className="enterprise-card p-10 space-y-8 relative overflow-hidden group bg-slate-900 text-white shadow-2xl">
                <div className="absolute top-0 right-0 p-8 opacity-5 group-hover:scale-110 transition-transform duration-[2s]">
                    <Terminal size={120} />
                </div>
                
                <div className="relative z-10 space-y-8">
                    <div className="flex items-center justify-between">
                         <div className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-[0.2em] bg-white/10 border border-white/20`}>
                             Hash: {log._id.slice(-8).toUpperCase()}
                         </div>
                         <Cpu size={24} className="text-blue-400 opacity-60" />
                    </div>

                    <div className="space-y-2">
                        <label className="text-[11px] font-black text-slate-500 uppercase tracking-widest">Operational Role</label>
                        <h3 className="text-[32px] font-black tracking-tighter leading-none italic uppercase">
                           {log.resource} <span className="text-blue-400">{log.action.split(' ')[0]}</span>
                        </h3>
                    </div>

                    <div className="grid grid-cols-2 gap-4 pt-10 border-t border-white/10">
                        <div>
                            <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1.5">Cipher Result</p>
                            <p className="text-[14px] font-black text-emerald-400 italic">SUCCESS_COMMIT</p>
                        </div>
                        <div>
                            <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1.5">Source Node</p>
                            <p className="text-[14px] font-black text-slate-200 italic uppercase">{log.role || 'Authority'}</p>
                        </div>
                    </div>
                </div>
            </div>

            {/* Authority Profile Card */}
            <div className="enterprise-card p-10 space-y-8 bg-white overflow-hidden relative group border border-slate-100 shadow-xl">
                 <div className="flex items-center gap-6">
                    <Avatar 
                        size={80} 
                        src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${log.user?.firstname}&backgroundColor=f1f5f9`} 
                        className="rounded-[28px] border-4 border-slate-50 shadow-inner" 
                    />
                    <div>
                        <div className="flex items-center gap-2 mb-1.5">
                           <ShieldCheck size={14} className="text-blue-600" />
                           <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Authorized Executive</span>
                        </div>
                        <h4 className="text-[22px] font-black text-slate-900 leading-none tracking-tighter">{log.user?.firstname} {log.user?.lastname}</h4>
                        <p className="text-[12px] text-slate-400 font-bold mt-2 uppercase tracking-tight">{log.user?.email}</p>
                    </div>
                 </div>
                 
                 <div className="pt-8 border-t border-slate-50 flex items-center justify-between">
                     <div className="flex items-center gap-3">
                        <Monitor size={16} className="text-slate-300" />
                        <span className="text-[11px] font-black text-slate-500 uppercase tracking-widest">IP Trace: Encrypted</span>
                     </div>
                     <Link to={`/superAdmin/profile/${log.user?._id}`}>
                        <Button type="text" className="text-blue-600 font-black uppercase text-[10px] tracking-widest p-0">Executive Profile →</Button>
                     </Link>
                 </div>
            </div>
            
            {/* Temporal Card */}
            <div className="enterprise-card p-8 bg-slate-50 border-none flex items-center justify-between">
                <div className="flex items-center gap-4">
                    <div className="w-12 h-12 rounded-2xl bg-white text-slate-900 border border-slate-100 flex items-center justify-center shadow-sm">
                        <Clock size={20} />
                    </div>
                    <div>
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Temporal Stamp</p>
                        <p className="text-[14px] font-black text-slate-900">{timestamp.toLocaleString()}</p>
                    </div>
                </div>
            </div>
        </div>

        {/* Right Column: Execution Payload */}
        <div className="xl:col-span-8">
            <div className="bg-white rounded-[48px] border border-slate-100 overflow-hidden shadow-2xl relative">
                <div className="p-10 border-b border-slate-50 flex items-center justify-between bg-slate-50/10">
                    <div className="flex items-center gap-4">
                        <div className="w-12 h-12 rounded-[18px] bg-slate-900 text-white flex items-center justify-center shadow-lg">
                            <Database size={24} />
                        </div>
                        <div>
                            <h3 className="text-[18px] font-black text-slate-900 leading-none uppercase tracking-tighter">Payload Analysis</h3>
                            <p className="text-[12px] text-slate-400 font-bold mt-1 uppercase tracking-widest italic">Inspection of raw commit data and resource structure</p>
                        </div>
                    </div>
                    <div className="flex items-center gap-2 bg-blue-50 px-4 py-2 rounded-2xl border border-blue-100">
                        <div className="w-2 h-2 rounded-full bg-blue-500 animate-pulse" />
                        <span className="text-[11px] font-black text-blue-600 uppercase tracking-widest italic">Data integrity verified</span>
                    </div>
                </div>

                <div className="p-12 space-y-10 min-h-[500px]">
                    {/* Render visual content if product/doc */}
                    {(log.resource === 'Product' || log.resource === 'Document') && (
                        <div className="space-y-6">
                            <label className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
                               <Layers size={14} /> Attachment Visualizer
                            </label>
                            <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                                { /* Generic Image Extraction from common paths */
                                  (() => {
                                      const imgs = [];
                                      const traverse = (obj) => {
                                          if (!obj || typeof obj !== 'object') return;
                                          if (obj.secure_url) imgs.push(obj.secure_url);
                                          Object.values(obj).forEach(v => traverse(v));
                                      };
                                      traverse(log.details);
                                      return imgs.slice(0, 4).map((url, i) => (
                                          <div key={i} className="group/img relative aspect-square rounded-[32px] overflow-hidden bg-slate-50 border border-slate-100 cursor-pointer shadow-inner" onClick={() => openModal(url)}>
                                             <img src={url} className="w-full h-full object-cover transition-all duration-700 group-hover/img:scale-110 group-hover/img:brightness-50" />
                                             <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover/img:opacity-100 transition-opacity">
                                                 <Search size={28} className="text-white drop-shadow-2xl" />
                                             </div>
                                          </div>
                                      ));
                                  })()
                                }
                            </div>
                        </div>
                    )}

                    {/* Action-Specific Highlight */}
                    <div className="enterprise-card p-10 bg-slate-50 border-none shadow-none relative overflow-hidden group">
                        <div className="absolute top-0 left-0 w-1.5 h-full bg-blue-600" />
                        <div className="flex items-center gap-6 mb-8">
                            <div className="w-14 h-14 bg-white rounded-2xl flex items-center justify-center border border-slate-100 shadow-sm">
                                <Zap size={24} className="text-blue-600" />
                            </div>
                            <div>
                                <h4 className="text-[20px] font-black text-slate-900 leading-none uppercase tracking-tighter italic">Instruction Summary</h4>
                                <p className="text-[12px] text-slate-400 font-bold mt-1 uppercase tracking-widest">{log.action}</p>
                            </div>
                        </div>

                        {/* Detail Matrix */}
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-x-12 gap-y-6">
                            {Object.entries(log.details || {}).map(([key, value]) => {
                                if (typeof value === 'object') return null;
                                return (
                                    <div key={key} className="flex flex-col gap-1 border-b border-slate-200/50 pb-4">
                                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{key.replace(/([A-Z])/g, ' $1').trim()}</label>
                                        <p className="text-[14px] font-black text-slate-800 break-all">{String(value)}</p>
                                    </div>
                                );
                            })}
                        </div>
                    </div>

                    {/* Raw JSON Trace */}
                    <div className="space-y-4">
                        <label className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
                            <Terminal size={14} /> Full Cipher Registry
                        </label>
                        <div className="p-8 rounded-[32px] bg-slate-900 border border-white/5 font-mono text-[12px] text-blue-400/80 overflow-x-auto leading-relaxed whitespace-pre shadow-2xl">
                           {JSON.stringify(log.details, null, 2)}
                        </div>
                    </div>
                </div>

                <div className="absolute inset-0 z-0 opacity-[0.02] pointer-events-none" 
                     style={{ backgroundImage: 'radial-gradient(#1e293b 1px, transparent 1px)', backgroundSize: '32px 32px' }} />
            </div>
        </div>
      </div>

      <ImageModal isOpen={isModalOpen} imageUrl={selectedImage} onClose={closeModal} />
      
      <style>{`
        .enterprise-card {
           background: #ffffff;
           border-radius: 40px;
           box-shadow: 0 10px 30px rgba(0,0,0,0.02);
        }
      `}</style>
    </div>
  );
};

export default ActivityDetail;
